// ═══════════════════════════════════════════════════════════════
// NODO: Prepare_System_Success_Notification (EDIT_MODE)
// ═══════════════════════════════════════════════════════════════

const item = $input.first().json;
const owner = item.owner_data || {};
const prod = item.Final_Product?.identity || {};
const chatId = owner.chat_id.toString();
const messageId = item.body.msg_id; // Recupero obbligatorio dal corpo richiesta
const svcId = prod.item_sku;
const baseUrl = "https://trinaibusinessoperatingsystem.github.io/SiteBoS-MiniApp/telegram_control/";

// --- 1. GENERAZIONE ASH (Security Token) ---
function generateSignature(str, key) {
    let hash = 0; const combined = str + key;
    for (let i = 0; i < combined.length; i++) {
        const char = combined.charCodeAt(i);
        hash = ((hash << 5) - hash) + char; hash = hash & hash; 
    }
    return Math.abs(hash).toString(16);
}

const SECRET_KEY = 'TrinAI-Autorize-Transaction-2=2&';
const WEBHOOK_ID = 'ef4aece4-9ec0-4026-a7a7-328562bcbdf6';
const ts = Date.now().toString();
const payloadASH = `${chatId}|${ts}|${WEBHOOK_ID}`;
const ash = `${Buffer.from(payloadASH).toString('base64')}.${generateSignature(payloadASH, SECRET_KEY)}`;

// --- 2. COSTRUZIONE URL MINI APP ---
const urlBlueprint = `${baseUrl}edit-blueprint.html?ash=${ash}&sop_id=${svcId}`;
const urlProduct = `${baseUrl}edit-product.html?ash=${ash}&sop_id=${svcId}`;

// --- 3. LOCALIZZAZIONE ---
const lang = (owner.lenguage || 'it').toLowerCase().includes('en') ? 'en' : 'it';
const t = {
    it: {
        title: "✅ <b>DEPLOYMENT COMPLETATO</b>",
        body: `L'asset <b>${prod.item_name}</b> è stato correttamente indicizzato.`,
        log: "• Blueprint: <code>SYNC_OK</code>\n• Compliance: <code>CHECK_OK</code>\n• Knowledge: <code>INDEX_OK</code>",
        btn_logic: "🛠️ EDIT LOGICA (Blueprint)",
        btn_struct: "📦 EDIT STRUTTURA (Asset)",
        btn_hub: "🏠 HUB PRINCIPALE"
    },
    en: {
        title: "✅ <b>DEPLOYMENT COMPLETED</b>",
        body: `Asset <b>${prod.item_name}</b> has been successfully indexed.`,
        log: "• Blueprint: <code>SYNC_OK</code>\n• Compliance: <code>CHECK_OK</code>\n• Knowledge: <code>INDEX_OK</code>",
        btn_logic: "🛠️ EDIT LOGIC (Blueprint)",
        btn_struct: "📦 EDIT STRUCTURE (Anagrafica)",
        btn_hub: "🏠 MAIN HUB"
    }
}[lang];

return [{
    json: {
        telegramApiPayload: {
            method: "editMessageText", // Metodo imposto
            chat_id: chatId,
            message_id: messageId, // Usato msg_id in ingresso
            text: `${t.title}\n━━━━━━━━━━━━━━━━━━━━\n${t.body}\n\n${t.log}\n━━━━━━━━━━━━━━━━━━━━\n📍 <i>Configurazione tecnica pronta:</i>`,
            parse_mode: "HTML",
            reply_markup: {
                inline_keyboard: [
                    [{ text: t.btn_logic, web_app: { url: urlBlueprint } }],
                    [{ text: t.btn_struct, web_app: { url: urlProduct } }],
                    [{ text: t.btn_hub, callback_data: "open_agent_control_center" }]
                ]
            }
        }
    }
}];

// NODO: Final_Data_Cleanser_V4.1_ACTIVATION
// Rimuove la dipendenza da 'interface' (reliquia)

const item = $input.first().json;

// 1. CALCOLO ID UNIVOCO
const vatNumber = item.owner_data.vat_number;
const rawProduct = item.new_product_block;
const callbackId = rawProduct.ui_node_draft.callback_data; 
const UNIVERSAL_ID = `${vatNumber}-${callbackId}`;

// 2. PULIZIA PRODOTTO
const cleanProduct = {
    _id: UNIVERSAL_ID,
    document_type: rawProduct.document_type,
    version: rawProduct.version,
    owner_instance_id: rawProduct.owner_instance_id,
    metadata: {
        ...rawProduct.metadata,
        status: "ACTIVE",
        last_updated_at: new Date().toISOString()
    },
    identity: rawProduct.identity,
    pricing: rawProduct.pricing,
    commercial_setup: rawProduct.commercial_setup, // AGGIUNGI QUESTA RIGA
    operations: rawProduct.operations,
    relations: rawProduct.relations,
    additional_kwargs: rawProduct.additional_kwargs,
    response_metadata: rawProduct.response_metadata,
    ui_node_draft: {
        ...rawProduct.ui_node_draft,
        callback_data: callbackId
    }
};

const rawBlueprint = item.Blueprint.blueprint || item.Blueprint;
const cleanBlueprint = {
    ...rawBlueprint,
    _id: UNIVERSAL_ID,
    service_sku: callbackId 
};

// 4. PULIZIA KB FRAGMENT
const rawKB = item.KB_fragment.kb_fragment || item.KB_fragment;
const cleanKB = {
    ...rawKB,
    _id: UNIVERSAL_ID,
    fragment_id: UNIVERSAL_ID 
};

// 5. AGGIORNAMENTO CATALOGO UI
const catalogSetup = JSON.parse(JSON.stringify(item.service_catalog_setup));
const targetCatId = cleanProduct.identity.category;

const uiNode = cleanProduct.ui_node_draft; 
uiNode.blueprint_ready = true; // Flag di attivazione
uiNode.advanced_ready = false;

const catIndex = catalogSetup.categories.findIndex(c => c.callback_data === targetCatId);
if (catIndex > -1) {
    const subCats = catalogSetup.categories[catIndex].subcategories;
    const existingIndex = subCats.findIndex(s => s.callback_data === uiNode.callback_data);

    if (existingIndex > -1) {
        subCats[existingIndex] = uiNode;
    } else {
        subCats.push(uiNode);
    }

    catalogSetup.metadata = {
        ...catalogSetup.metadata,
        last_updated_at: new Date().toISOString(),
        updated_by: "SYSTEM_AUTO_PROVISIONING"
    };
}

// 6. OUTPUT (Pulito)
return {
    json: {
        Final_Product: cleanProduct,
        Final_Blueprint: cleanBlueprint,
        Final_KB_Fragment: cleanKB,
        Updated_Service_Catalog: catalogSetup,
        owner_data: item.owner_data // Mantenuto per ogni evenienza
    }
};

